#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_kernel(const T * __restrict__ in,
                   T * __restrict__ out,
                   const T * __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    int blockIdx_x = omp_get_team_num();
    #pragma omp parallel num_threads(bs)
    {
      int threadIdx_x = omp_get_thread_num();
      int i = threadIdx_x + blockIdx_x * bs;
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (0 <= start + j && start + j < input_width) {
          s += in[start + j] * mask[j];
        }
      }
      out[i] = s;
    }
  }
}

