#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_kernel(const T * __restrict__ in,
                         T * __restrict__ out,
                   const T * __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  int grids = input_width / bs;
#pragma omp target teams distribute parallel for num_teams(grids) thread_limit(bs) is_device_ptr(in, out, mask)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_kernel(const T * __restrict__ in,
                               T * __restrict__ out,
                         const T * __restrict__ mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  int grids = input_width / bs;
#pragma omp target teams distribute parallel for num_teams(grids) thread_limit(bs) is_device_ptr(in, out, mask)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_caching_kernel(const T * __restrict__ in,
                                       T * __restrict__ out,
                                 const T * __restrict__ mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  int grids = input_width / bs;
#pragma omp target teams distribute parallel for num_teams(grids) thread_limit(bs) is_device_ptr(in, out, mask)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
