#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <omp.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time - t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  #pragma omp parallel for collapse(2)
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
      int vp0 = ((y + 1) % Ly) * Lx + x;
      int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
      out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

int main(int argc, char *argv[]) {

  if (argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  const int N = Lx * Ly;
  float *buffer = (float*) malloc(sizeof(float) * N);
  float *h_out  = (float*) malloc(sizeof(float) * N);
  float *h_in   = (float*) malloc(sizeof(float) * N);
  float *d_res  = (float*) malloc(sizeof(float) * N);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * N);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_in  = (float*) malloc(sizeof(float) * N);
  float *d_out = (float*) malloc(sizeof(float) * N);
  memcpy(d_in, buffer, sizeof(float) * N);

  double t0 = 0.0;
  int ping = 0;

  #pragma omp target data map(to: d_in[0:N]) map(alloc: d_out[0:N])
  {
    t0 = stop_watch(0);

    for (i = 0; i < niter; i++) {
      if (ping == 0) {
        #pragma omp target teams distribute parallel for
        for (int idx = 0; idx < N; idx++) {
          int xx = idx % Lx;
          int yy = idx / Lx;
          int v00 = yy * Lx + xx;
          int v0p = yy * Lx + (xx + 1) % Lx;
          int v0m = yy * Lx + (Lx + xx - 1) % Lx;
          int vp0 = ((yy + 1) % Ly) * Lx + xx;
          int vm0 = ((Ly + yy - 1) % Ly) * Lx + xx;
          d_out[v00] = xnorm * d_in[v00] + xdelta * (d_in[v0p] + d_in[v0m] + d_in[vp0] + d_in[vm0]);
        }
      } else {
        #pragma omp target teams distribute parallel for
        for (int idx = 0; idx < N; idx++) {
          int xx = idx % Lx;
          int yy = idx / Lx;
          int v00 = yy * Lx + xx;
          int v0p = yy * Lx + (xx + 1) % Lx;
          int v0m = yy * Lx + (Lx + xx - 1) % Lx;
          int vp0 = ((yy + 1) % Ly) * Lx + xx;
          int vm0 = ((Ly + yy - 1) % Ly) * Lx + xx;
          d_in[v00] = xnorm * d_out[v00] + xdelta * (d_out[v0p] + d_out[v0m] + d_out[vp0] + d_out[vm0]);
        }
      }
      ping = 1 - ping;
    }

    t0 = stop_watch(t0) / (double)niter;

    printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
           niter, Lx, Ly, t0,
           Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
           (Lx * Ly * 6.0) / (t0 * 1.0e3));

    if (ping == 0) {
      #pragma omp target update from(d_in[0:N])
    } else {
      #pragma omp target update from(d_out[0:N])
    }
  }

  if (ping == 0) {
    memcpy(d_res, d_in, sizeof(float) * N);
  } else {
    memcpy(d_res, d_out, sizeof(float) * N);
  }

  bool ok = true;
  for (i = 0; i < N; i++) {
    if (fabs(h_in[i] - d_res[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(d_in);
  free(d_out);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

