  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * N);

  for (i = 0; niter > i; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

