  double t0 = stop_watch(0);

  for (i = 0; niter > i; i++) {
    if ((i & 1) == 0) {
      #pragma omp target teams distribute parallel for
      for (int idx = 0; idx < N; idx++) {
        int x = idx % Lx;
        int y = idx / Lx;
        int v00 = y * Lx + x;
        int v0p = y * Lx + (x + 1) % Lx;
        int v0m = y * Lx + (Lx + x - 1) % Lx;
        int vp0 = ((y + 1) % Ly) * Lx + x;
        int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
        d_out[v00] = xnorm * d_in[v00] + xdelta * (d_in[v0p] + d_in[v0m] + d_in[vp0] + d_in[vm0]);
