      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  #pragma omp target exit data map(delete:d_in[0:N]) map(delete:d_out[0:N])

  free(d_in);
  free(d_out);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <omp.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time - t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  #pragma omp parallel for collapse(2)
  for (int y = 0; Ly > y; y++) {
    for (int x = 0; Lx > x; x++) {
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
      int vp0 = ((y + 1) % Ly) * Lx + x;
      int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
      out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

int main(int argc, char *argv[]) {

  if (4 != argc) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (0 != Lx % NTX || 0 != Ly % NTY) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  float *buffer = (float *) malloc(sizeof(float) * Lx * Ly);
  float *h_out = (float *) malloc(sizeof(float) * Lx * Ly);
  float *h_in  = (float *) malloc(sizeof(float) * Lx * Ly);
  float *d_res = (float *) malloc(sizeof(float) * Lx * Ly);

  int i, j, x, y;
  for (i = 0; Lx > i; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; Ly > i; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * Lx * Ly);

  for (i = 0; niter > i; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  const size_t bytes = sizeof(float) * (size_t)Lx * (size_t)Ly;
  const int dev = omp_get_default_device();
  const int host = omp_get_initial_device();

  float *d_in = (float *) omp_target_alloc(bytes, dev);
  float *d_out = (float *) omp_target_alloc(bytes, dev);

  omp_target_memcpy(d_in, buffer, bytes, 0, 0, dev, host);

  double t0 = stop_watch(0);

  for (i = 0; niter > i; i++) {
    #pragma omp target teams distribute parallel for is_device_ptr(d_out, d_in)
    for (int idx = 0; idx < Lx * Ly; idx++) {
      int x = idx % Lx;
      int y = idx / Lx;
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
      int vp0 = ((y + 1) % Ly) * Lx + x;
      int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
      d_out[v00] = xnorm * d_in[v00] + xdelta * (d_in[v0p] + d_in[v0m] + d_in[vp0] + d_in[vm0]);
    }
    std::swap(d_out, d_in);
  }

  t0 = stop_watch(t0) / (double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  omp_target_memcpy(d_res, d_in, bytes, 0, 0, host, dev);

  bool ok = true;
  for (i = 0; Lx * Ly > i; i++) {
    if (fabs(h_in[i] - d_res[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  omp_target_free(d_in, dev);
  omp_target_free(d_out, dev);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

