}

void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  int num_blocks = (n_explorers + _QUEENS_BLOCK_SIZE_ - 1) / _QUEENS_BLOCK_SIZE_;

  printf("\n### Regular BP-DFS search. ###\n");

  if (n_explorers == 0) {
    auto start = std::chrono::steady_clock::now();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);
    return;
  }

  const int dev = omp_get_default_device();
  const int host = omp_get_initial_device();

  unsigned long long *vector_of_tree_size_d =
      (unsigned long long*)omp_target_alloc((size_t)n_explorers * sizeof(unsigned long long), dev);
  unsigned long long *sols_d =
      (unsigned long long*)omp_target_alloc((size_t)n_explorers * sizeof(unsigned long long), dev);
  QueenRoot *root_prefixes_d =
      (QueenRoot*)omp_target_alloc((size_t)n_explorers * sizeof(QueenRoot), dev);

  if (!vector_of_tree_size_d || !sols_d || !root_prefixes_d) {
    printf("Error: device out of memory\n");
    if (vector_of_tree_size_d) omp_target_free(vector_of_tree_size_d, dev);
    if (sols_d) omp_target_free(sols_d, dev);
    if (root_prefixes_d) omp_target_free(root_prefixes_d, dev);
    exit(1);
  }

  omp_target_memcpy(root_prefixes_d, root_prefixes_h,
                    (size_t)n_explorers * sizeof(QueenRoot),
                    0, 0, dev, host);

  auto start = std::chrono::steady_clock::now();

  for (int it = 0; it < repeat; it++) {
#pragma omp target teams distribute parallel for thread_limit(_QUEENS_BLOCK_SIZE_) num_teams(num_blocks) \
    is_device_ptr(root_prefixes_d, vector_of_tree_size_d, sols_d)
    for (int idx = 0; idx < (int)n_explorers; idx++) {
      unsigned int flag = 0;
      unsigned int bit_test = 0;
      char vertice[20];
      int N_l = size;
      int i, depth;
      unsigned long long qtd_solutions_thread = 0ULL;
      int depthGlobal = initial_depth;
      unsigned long long tree_size = 0ULL;

      for (i = 0; i < N_l; ++i) {
        vertice[i] = _EMPTY_;
      }

      flag = root_prefixes_d[idx].control;

      for (i = 0; i < depthGlobal; ++i)
        vertice[i] = (char)root_prefixes_d[idx].board[i];

      depth = depthGlobal;

      do {
        vertice[depth]++;
        bit_test = 0;
        bit_test |= (1 << vertice[depth]);
        if (vertice[depth] == N_l) {
          vertice[depth] = _EMPTY_;
        } else if (!(flag & bit_test) && queens_stillLegal(vertice, depth)) {
          ++tree_size;
          flag |= (1ULL << vertice[depth]);
          depth++;
          if (depth == N_l) {
            ++qtd_solutions_thread;
          } else continue;
        } else continue;
        depth--;
        flag &= ~(1ULL << vertice[depth]);
      } while (depth >= depthGlobal);

      sols_d[idx] = qtd_solutions_thread;
      vector_of_tree_size_d[idx] = tree_size;
    }
  }

#pragma omp target update from(vector_of_tree_size_d[0:n_explorers], sols_d[0:n_explorers]) is_device_ptr(vector_of_tree_size_d, sols_d)

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  omp_target_memcpy(vector_of_tree_size_h, vector_of_tree_size_d,
                    (size_t)n_explorers * sizeof(unsigned long long),
                    0, 0, host, dev);
  omp_target_memcpy(sols_h, sols_d,
                    (size_t)n_explorers * sizeof(unsigned long long),
                    0, 0, host, dev);

  omp_target_free(vector_of_tree_size_d, dev);
  omp_target_free(sols_d, dev);
  omp_target_free(root_prefixes_d, dev);
}

