#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <stdint.h>
#include <omp.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

inline void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const char *board, int initialDepth, int num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; initialDepth > i;++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const char *board, const int r)
{
  for (int i = 0; r > i; ++i)
    if (board[r] == board[i]) return false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r-1; 0 <= i; --i) {
    --ld; ++rd;
    if (ld == board[i] || rd == board[i]) return false;
  }
  return true;
}

#pragma omp declare target
inline bool queens_stillLegal(const char *board, const int r)
{
  bool safe = true;

  for (int i = 0; r > i; ++i)
    if (board[r] == board[i]) safe = false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r-1; 0 <= i; --i) {
    --ld; ++rd;
    if (ld == board[i] || rd == board[i]) safe = false;
  }
  return safe;
}
#pragma omp end declare target

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; size > i; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do{
    vertice[nivel]++;
    bit_test = 0;
    bit_test = bit_test | (1<<vertice[nivel]);

    if(size == vertice[nivel]){
      vertice[nivel] = _EMPTY_;
    }else if ( MCstillLegal(vertice, nivel) && !(flag &  bit_test ) ){

      flag = flag | (1ULL<<vertice[nivel]);
      nivel++;
      ++local_tree;
      if (initialDepth == nivel){
        prefixesHandleSol(root_prefixes,flag,vertice,initialDepth,num_sol);
        num_sol++;
      }else continue;
    }else continue;

    nivel--;
    flag &= ~(1ULL<<vertice[nivel]);

  }while(0 <= nivel);

  *tree_size = local_tree;

  return num_sol;
}

void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h ,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  printf("\n### Regular BP-DFS search. ###\n");

  auto start = std::chrono::steady_clock::now();

  if (n_explorers > 0) {
    #pragma omp target data map(to: root_prefixes_h[0:n_explorers]) \
                            map(from: vector_of_tree_size_h[0:n_explorers], sols_h[0:n_explorers])
    {
      for (int it = 0; repeat > it; it++) {
        #pragma omp target teams distribute parallel for thread_limit(_QUEENS_BLOCK_SIZE_)
        for (unsigned int idx = 0; idx < n_explorers; ++idx) {
          unsigned int flag = 0;
          unsigned int bit_test = 0;
          char vertice[20];
          int N_l = size;
          int i, depth;
          unsigned long long qtd_solutions_thread = 0ULL;
          int depthGlobal = initial_depth;
          unsigned long long tree_size = 0ULL;

          #pragma unroll 2
          for (i = 0; N_l > i; ++i) {
            vertice[i] = _EMPTY_;
          }

          flag = root_prefixes_h[idx].control;

          #pragma unroll 2
          for (i = 0; depthGlobal > i; ++i)
            vertice[i] = (char)root_prefixes_h[idx].board[i];

          depth = depthGlobal;

          do {
            vertice[depth]++;
            bit_test = 0;
            bit_test = bit_test | (1<<vertice[depth]);
            if(N_l == vertice[depth]){
              vertice[depth] = _EMPTY_;
            } else if (!(flag & bit_test ) && queens_stillLegal(vertice, depth)){
              ++tree_size;
              flag = flag | (1ULL<<vertice[depth]);
              depth++;
              if (N_l == depth) {
                ++qtd_solutions_thread;
              } else continue;
            } else continue;
            depth--;
            flag = flag & (~(1ULL<<vertice[depth]));
          } while(depthGlobal <= depth);

          sols_h[idx] = qtd_solutions_thread;
          vector_of_tree_size_h[idx] = tree_size;
        }
      }
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);
}

int main(int argc, char *argv[])
{
  if (4 != argc) {
    printf("Usage: %s <size> <initial depth> <repeat>\n", argv[0]);
    return 1;
  }
  const short size = atoi(argv[1]);
  const int initialDepth = atoi(argv[2]);
  const int repeat = atoi(argv[3]);
  printf("\n### Initial depth: %d - Size: %d:", initialDepth, size);

  unsigned long long tree_size = 0ULL;
  unsigned long long qtd_sols_global = 0ULL;
  unsigned int nMaxPrefixos = 75580635;

  QueenRoot* root_prefixes_h = (QueenRoot*)malloc(sizeof(QueenRoot)*nMaxPrefixos);
  unsigned long long *vector_of_tree_size_h = (unsigned long long*)malloc(sizeof(unsigned long long)*nMaxPrefixos);
  unsigned long long *solutions_h = (unsigned long long*)malloc(sizeof(unsigned long long)*nMaxPrefixos);

  if (NULL == root_prefixes_h || NULL == vector_of_tree_size_h || NULL == solutions_h) {
    printf("Error: host out of memory\n");
    if (root_prefixes_h) free(root_prefixes_h);
    if (vector_of_tree_size_h) free(vector_of_tree_size_h);
    if (solutions_h) free(solutions_h);
    return 1;
  }

  unsigned long long n_explorers = BP_queens_prefixes(size, initialDepth, &tree_size, root_prefixes_h);

  nqueens(size, initialDepth, (unsigned int)n_explorers, root_prefixes_h, vector_of_tree_size_h, solutions_h, repeat);

  printf("\nTree size: %llu", tree_size );

  for(unsigned long long i = 0; n_explorers > i;++i){
    if(0 < solutions_h[i])
      qtd_sols_global = qtd_sols_global + (solutions_h[i]);
    if(0 < vector_of_tree_size_h[i])
      tree_size = tree_size + (vector_of_tree_size_h[i]);
  }

  printf("\nNumber of solutions found: %llu \nTree size: %llu\n", qtd_sols_global, tree_size );

  if (15 == size && 7 == initialDepth) {
    if (2279184 == qtd_sols_global && 171129071 == tree_size)
      printf("PASS\n");
    else
      printf("FAIL\n");
  }

  free(root_prefixes_h);
  free(vector_of_tree_size_h);
  free(solutions_h);
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include <omp.h>

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

const int max_iter = 1000;
const float threshold = 1e-16f;

void map_ref(const int *__restrict__ pages,
             const float *__restrict__ page_ranks,
             float *__restrict__ maps,
             const unsigned int *__restrict__ noutlinks,
             const int n)
{
  #pragma omp parallel for
  for (int i = 0; i < n; i++) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    for (int j = 0; j < n; ++j) {
      maps[(size_t)i * n + j] = pages[(size_t)i * n + j] * outbound_rank;
    }
  }
}

void reduce_ref(float *__restrict__ v_0,
                const float *__restrict__ maps,
                const int n,
                float *__restrict__ dif)
{
  const float D_FACTOR_LOCAL = 0.85f;
  #pragma omp parallel for
  for (int j = 0; j < n; j++) {
    float old_rank = v_0[j];
    float new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank += maps[(size_t)i * n + j];
    }

    new_rank = ((1.f - D_FACTOR_LOCAL) / n) + (D_FACTOR_LOCAL * new_rank);
    dif[j] = fmaxf(fabsf(new_rank - old_rank), dif[j]);
    v_0[j] = new_rank;
  }
}

int *random_pages(int n, unsigned int *noutlinks, int divisor) {
  int i, j, k;
  int *pages = (int *)malloc((size_t)n * n * sizeof(int));

  if (divisor <= 0) {
    fprintf(stderr, "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n", divisor);
    exit(1);
  }

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
    for (j = 0; j < n; ++j) {
      if (i != j && (abs(rand()) % divisor == 0)) {
        pages[(size_t)i * n + j] = 1;
        noutlinks[i] += 1;
      }
    }

    if (noutlinks[i] == 0) {
      do { k = abs(rand()) % n; } while (k == i);
      pages[(size_t)i * n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val) {
  for (int i = 0; i < n; ++i) {
    a[i] = val;
  }
}

void usage(char *argv[]) {
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
                  " [-t threshold] [-q divisor for zero density]\n", argv[0]);
}

static struct option size_opts[] =
{
  {"number of pages", 1, NULL, 'n'},
  {"max number of iterations", 1, NULL, 'i'},
  {"minimum threshold", 1, NULL, 't'},
  {"divisor for zero density", 1, NULL, 'q'},
  {0, 0, 0}
};

float maximum_dif(float *difs, int n) {
  float max = 0.0f;
  for (int i = 0; i < n; ++i) {
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while ((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1) {
    switch (opt) {
      case 'n':
        n = atoi(optarg);
        break;
      case 'i':
        iter = atoi(optarg);
        break;
      case 't':
        thresh = atof(optarg);
        break;
      case 'q':
        divisor = atoi(optarg);
        break;
      default:
        usage(argv);
        exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);
  size_t page_size = (size_t)n * n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float *)malloc(rank_size);
  maps = (float *)malloc(map_size);
  noutlinks = (unsigned int *)malloc(link_size);

  max_diff = max_diff_ref = 99.0f;

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n, noutlinks, divisor);
  init_array(page_ranks, n, 1.0f / (float)n);

  float *diffs = (float *)malloc(rank_size);

  int dev = omp_get_default_device();
  int host = omp_get_initial_device();

  int *d_pages = (int *)omp_target_alloc(page_size, dev);
  float *d_maps = (float *)omp_target_alloc(map_size, dev);
  float *d_page_ranks = (float *)omp_target_alloc(rank_size, dev);
  float *d_diffs = (float *)omp_target_alloc(rank_size, dev);
  unsigned int *d_noutlinks = (unsigned int *)omp_target_alloc(link_size, dev);

  omp_target_memcpy(d_pages, pages, page_size, 0, 0, dev, host);
  omp_target_memcpy(d_page_ranks, page_ranks, rank_size, 0, 0, dev, host);
  omp_target_memcpy(d_noutlinks, noutlinks, link_size, 0, 0, dev, host);
  memset(diffs, 0, rank_size);
  omp_target_memcpy(d_diffs, diffs, rank_size, 0, 0, dev, host);

  size_t block_size = n < BLOCK_SIZE ? n : BLOCK_SIZE;
  size_t num_blocks = (n + block_size - 1) / block_size;
  (void)block_size;
  (void)num_blocks;

  double ktime = 0.0;
  printf("Threshold: %f\n", thresh);

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    #pragma omp target teams distribute parallel for is_device_ptr(d_pages, d_page_ranks, d_maps, d_noutlinks)
    for (int ii = 0; ii < n; ++ii) {
      float outbound_rank = d_page_ranks[ii] / (float)d_noutlinks[ii];
      for (int j = 0; j < n; ++j) {
        d_maps[(size_t)ii * n + j] = d_pages[(size_t)ii * n + j] * outbound_rank;
      }
    }

    #pragma omp target teams distribute parallel for is_device_ptr(d_page_ranks, d_maps, d_diffs)
    for (int j = 0; j < n; ++j) {
      float old_rank = d_page_ranks[j];
      float new_rank = 0.0f;
      for (int ii = 0; ii < n; ++ii) {
        new_rank += d_maps[(size_t)ii * n + j];
      }

      new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
      d_diffs[j] = fmaxf(fabsf(new_rank - old_rank), d_diffs[j]);
      d_page_ranks[j] = new_rank;
    }

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    omp_target_memcpy(diffs, d_diffs, rank_size, 0, 0, host, dev);
    max_diff = maximum_dif(diffs, n);
  }

  omp_target_free(d_pages, dev);
  omp_target_free(d_maps, dev);
  omp_target_free(d_page_ranks, dev);
  omp_target_free(d_noutlinks, dev);
  omp_target_free(d_diffs, dev);

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t = 1; t <= iter && max_diff_ref >= thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }

  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);

  return 0;
}

